var f = this, id = f.get_id(), c = 'd56', g = f._g$ = f.getItem(c)._controlBehavior, t = $func.trim(f.getItemValue('loai_ct')), errorMessage, v = f._language == 'v';
if (t == '1') {
  var d1 = f.getItemValue('ngay_lct');
  for (var row = 1; row <= g._rowCount; row ++) {
    var d2 = g._getItemValue(row, g._getColumnOrder('ngay_hd'));
    if (d1 != null && d2 != null && d1 < d2) {
      g._errorObject = g._getItem(row, g._getColumnOrder('ngay_hd'));
      errorMessage = (v ? 'Trường <span class="Highlight">ngày hóa đơn</span> phải nhỏ hơn <span class="Highlight">ngày lập chứng từ</span>.' : '<span class="Highlight">Invoice date</span> must be less than <span class="Highlight">voucher date</span>.');
      $func.hideWait(id);
      f.focus(c);
      f._checked = false;
      $message.show(errorMessage, String.format('$find(\'{0}\')._errorObject.focus()', g.get_id()));
      break;
    }
  }
}
