      /* <flatten type="Javascript"> */
function init$Voucher$(f) {initialize(f, 'ong_ba', null, 'loai_ct', 'status');}
/* </flatten> */
function active$Voucher$(f) {&ScriptActiveVoucher;
  for (var i = 0; i < f._$length.length; i ++) {
    var a = f._$length[i];
    f.getItem(a[0]).maxLength = a[1];
  }
  f.getItem('d56')._controlBehavior.add_onRender(on$Voucher$GridRender);
  f.getItem('f56')._controlBehavior.add_onRender(on$Voucher$ChargeRender);
  f._tabContainer.add_activeTabChanged(onChange$Voucher$Tab);
  f._tabContainer._loaded = true;
&PaymentRequestCustomerIdentity;
      &APVSetReadOnlyFields;
      &APVHandleStatus;
      &VoucherLogHandleStatus;
      &ListCreate;
      &PostCreate;

}
function scatter$Voucher$(f) {
  &ScriptScatterVoucher;
      &PaymentRequestCustomerIdentity;
      &APVSetReadOnlyFields;&VoucherLogHandleStatus;
}
function close$Voucher$(f) {
&ScriptCloseVoucher;
      &ListDispose;
      &PostDispose;
  if (f._tabContainer) try {f._tabContainer.remove_activeTabChanged(onChange$Voucher$Tab);} catch (ex) {}
  try {f.getItem('d56')._controlBehavior.remove_onRender(on$Voucher$GridRender);} catch (ex) {}
  try {f.getItem('f56')._controlBehavior.remove_onRender(on$Voucher$ChargeRender);} catch (ex) {}
}
function on$Voucher$ExecuteCommand(sender, e) {
  var action = e.type.Action, f = sender, g = f.getItem('d56')._controlBehavior, y = f.getItem('f56')._controlBehavior, z = f.getItem('r30')._controlBehavior&DeductibleExecuteCommandVar;;
  switch (action) {
    case 'Shown':
      &ListShown;
      &PostShown;
      break;
    case 'Save':
      &DeductibleCheckVoucherType;
      if (!check$GridDetailTax$VoucherType(f, e, g, ['9'])) break;
      set$Voucher$EmptyControlField(f, g, 'so_hd', '1');
      set$Voucher$EmptyControlField(f, g, 'ma_kh_i', '3');
      break;
    case 'Gather':
      g.setSequenceNumber('line_nbr');
      g.setContinuance('stt_rec0');
      y.setSequenceNumber('line_nbr');
      y.setContinuance('stt_rec0');
      z.setSequenceNumber('line_nbr');
      z.setContinuance('stt_rec0');
      &DeductibleExecuteCommand;
      break;
    case 'Explore':
      &APVAddStatus;
      &VoucherLogHandleStatusExplore;
      break;
    default:
      break;
  }
}
/* <flatten type="Javascript"> */
function on$Voucher$GridRender(sender, eventArgs) {set$Voucher$GridColumns(eventArgs.grid);}
/* </flatten> */
      &ScriptVoucherNumber;
      &ScriptExchangeRate;

objectBehavior$Voucher$Currency = {
&ScriptCurrency;
  create: function(f) {
    var d = f.getItem('ngay_lct'), p = f.getItem('ngay_ct'), c = f.getItem('ma_nt'), r = f.getItem('ty_gia'), g = f.getItem('d56')._controlBehavior, y = f.getItem('f56')._controlBehavior, z = f.getItem('r30')._controlBehavior&DeductibleExecuteCommandVar;;
    var v = f._currencyBehavior = $create(FastBusiness.AjaxControlExtender.ExchangeRate, {id: f._id + '_currencyBehavior', currencyDate: d, referenceDate: p, exchangeRate: r, form: f, baseCurrency: f._baseCurrency}, null, null, c);
    v.set_currencyFields('t_tien_nt,t_thue_nt,t_tt_nt:t_tien,t_thue,t_tt');
    v.addGridFields(g, 'tien_nt, thue_nt, tt_nt:tien, thue, tt');
    v.addGridFields(y, 'tien_cp_nt,t_thue_nt:tien_cp,t_thue');
    v.addGridFields(z, 't_tien_nt,t_thue_nt:t_tien,t_thue');
    &DeductibleExecuteCommandCurrency;&ScriptTaxGridDetailCurrencyTotalFields;

    v.set_referenceFields(null);
    &ScriptTaxGridDetailCurrencyExpression;
    v.init();
    v.setFormLayout(0);
    this.init(f);
  },
  onCurrencyChanged: function(sender, e) {
    this.onCurrencySelected(sender, e);
    var c = e.object, f = c._currency.parentForm;
    if (c._baseCurrency == e.type) {
      c._exchangeRate._controlBehavior._set_number(1);
      c.onExchangeRateChanged();
    }
    else {
      var d = f.getItemValue('ngay_lct');
      if (d) f.request('GetExchangeRate', 'GetExchangeRate', ['ma_nt', 'ngay_lct']);
    }
    set$Voucher$DependOnVoucherType(f);
    set$Voucher$ChargeColumn(f, 'f56', ['ty_gia']);
  },
  onDateChanged: function(sender, e) {
    var c = e.object, f = c._currency.parentForm;
    if (e.type && (c._currency.value != c._baseCurrency)) f.request('GetExchangeRate', 'DateChanged', ['ma_nt', 'ngay_lct']);
  },
  onCurrencySelected: function(sender, e) {
    if (e.object._baseCurrency == e.type) {
      e.object._form.focusWhenTabChanged([['d56', 'hd_yn'], ['r30', 'hd_yn'], 'ma_tt'&DeductibleOnchangeTab;, ['f56', 'hd_yn'], 'ten_dv'&APVTabChange;&ListTabChange;&PostTabChange;]);
      &PostCurrencySelected;
    }
  }
}



function onChange$Voucher$Tab(sender, e) {
  sender.parentForm.focusWhenTabChanged(['d56', 'r30', 'ma_tt'&DeductibleOnchangeTab;, 'f56', 'ten_dv'&APVTabChange;&ListTabChange;&PostTabChange;]);
  &PostTabFocus;
}
/* <flatten type="Javascript"> */
function onChange$Voucher$Customer(o) {
  var f = o.parentForm, v = $func.trim(f.getItemValue('loai_ct'));
  f.request('Customer', 'Customer', ['ma_kh'], o);
  if (v == 1) set$Voucher$Customer$EmptyInvoice(f.getItem('d56')._controlBehavior, 'so_hd', 'tk_no');
}
function onChange$Voucher$Date(o) {
  var f = o.parentForm; v = $func.trim(f.getItemValue('loai_ct')), g = f.getItem('d56');
  if (v == 1 && g && g._activeCell) set$Voucher$Customer$KeyFilter(g._controlBehavior, 'so_hd');
}
function onChange$Voucher$Memo(o) {
  var g = o.parentForm.getItem('d56')._controlBehavior;
  if ((o.parentForm._action == 'New') && (g._rowCount > 0) && (g._getItemValue(1, g._getColumnOrder('dien_giai')) == ''))
    g._getItem(1, g._getColumnOrder('dien_giai')).value = o.value;
  if (o.parentForm.getItem("noi_dung").value == '')
    o.parentForm.setItemControlBehavior('noi_dung', o.value, null, true);
}
function onChange$Voucher$VoucherType(o) {
  var f = o.parentForm;
  set$Voucher$DependOnVoucherType(f);
  set$Voucher$ChargeColumn(f, 'f56', ['ty_gia']);
}
function onchange$Item$(o) {
  if (o.value == '2') {
    var f = o.parentForm, g = f.getItem('d56')._controlBehavior, r = g._rowCount, c = 'tk_no';
    if (r == 1 && g._getItemValue(1, g._getColumnOrder(c)) == '') {
      var i = g._getItem(r, 1);
      i.row = r;
      g.setItemGridBehavior(i, [[c, f.getItemValue('tk_ex'), f.getItemValue('ten_tk_ex'), false]]);
    }
  }
}
/* </flatten> */
function on$Voucher$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Loading':
      &VoucherNumberLoading;
      &APVSetVoucherDefaultValue;
      set$Voucher$ExchangeRateLabel(f);
      set$Voucher$ExchangeRateDisabled(f);
      set$Voucher$PaymentControl(f);
      break;
    case 'Scattering':
      &VoucherNumberScattering;
      &APVSetVoucherDefaultValue;
      &ListScattering;
      &PostScattering;
      set$Voucher$DependOnVoucherType(f);
      set$Voucher$PaymentControl(f);
      break;
    case 'Navigating':
      &ListRefresh;
      &PostRefresh;
      set$Voucher$ExchangeRateLabel(f);
      break;

      &VoucherNumberReading;
      &CurrencyResponse;
      &ListResponseTicket;

    case 'Customer':
      f.setItemControlBehavior('ma_tt0', result[0].Value, result[1].Value, true);
      f.setItemControlBehavior('ong_ba', result[2].Value, null, true);
      f.setItemControlBehavior('dia_chi', result[3].Value, null, true);
      f.setItemControlBehavior('ma_so_thue', result[4].Value, null, true);
      f.setItemControlBehavior('ten_ncc', result[5].Value, null, true);

      f.setItemControlBehavior('ten_dv', result[5].Value, null, true);
      f.setItemControlBehavior('tk_nh', result[6].Value, null, true);
      f.setItemControlBehavior('ngan_hang', result[7].Value, null, true);
      f.setItemControlBehavior('tinh_thanh', result[8].Value, null, true);

      f.setItemValues('tk_ex, ten_tk_ex', [result[9].Value, result[10].Value]);
      onchange$Item$(f.getItem('loai_ct'));

      f.live(f.getItem('dia_chi'));
